mapper.select:
SELECT DISTINCT o.order_id, o.user_id, o.total_amount, o.address_id, o.status, o.created_at, o.updated_at FROM orders o JOIN order_items oi ON oi.order_id = o.order_id JOIN products p ON p.product_id = oi.product_id WHERE p.seller_id = #{seller_id}
AND oi.status = #{status}
ORDER BY o.order_id DESC

SELECT oi.order_item_id, oi.order_id, oi.product_id, oi.price, oi.quantity, oi.status, oi.confirmed_at, oi.updated_at, p.name AS productName, p.image_l AS imageL, (oi.price * oi.quantity) AS subtotalAmount FROM order_items oi JOIN products p ON p.product_id = oi.product_id WHERE oi.order_id = #{order_id} AND p.seller_id = #{seller_id}
AND oi.status = #{status}
ORDER BY oi.order_item_id ASC
